async (params, browser) => {
  // Open Bandcamp search
  await browser.open(`https://bandcamp.com/search?q=${params.query}`)

  // Wait for results
  await browser.waitForSelector('.result-items li.searchresult, .result-items', 15000)

  // Let results render
  await browser.wait(2500)

  // Extract results
  const search_results = await browser.evaluate(`const results = []; document.querySelectorAll('.result-items li.searchresult').forEach((el, i) => { if (i < 15) { const info = el.querySelector('.result-info'); const titleEl = info?.querySelector('.heading a'); const typeEl = info?.querySelector('.itemtype'); const urlEl = info?.querySelector('.itemurl a'); const subheadEl = info?.querySelector('.subhead'); const genreEl = info?.querySelector('.genre'); const tagsEl = info?.querySelector('.tags'); const releasedEl = info?.querySelector('.released'); const artEl = el.querySelector('.art img'); results.push({ name: titleEl?.textContent?.trim() || '', url: urlEl?.textContent?.trim() || titleEl?.href || '', type: typeEl?.textContent?.trim() || '', subhead: subheadEl?.textContent?.trim() || '', genre: genreEl?.textContent?.trim().replace(/^genre:\s*/i, '') || '', tags: tagsEl?.textContent?.trim().replace(/^tags:\s*/i, '') || '', released: releasedEl?.textContent?.trim().replace(/^released\s*/i, '') || '', image: artEl?.src || '' }); } }); return { query: '' + params.query + '', result_count: results.length, results };`)

  return search_results
}
